public int active()
{
    int ret;

    ret = next active();

    if(ETGACFParameters::find().EnableProvisionalCharges == NoYes::Yes)
    {
        FormDataSource formDS                     = this;
        FormDataSource formDataSource             = formDS.formRun().dataSource(formDataSourceStr(PurchAgreementcreate,PurchAgreementHeader));
        PurchAgreementHeader purchAgreementHeaderLoc = formDataSource.cursor();

        if(purchAgreementHeaderLoc.AgreementClassification)
        {
            AgreementClassification agreementClassification = AgreementClassification::find(purchAgreementHeaderLoc.AgreementClassification);
            if(agreementClassification.ETGIncoTerms == NoYes::Yes)
            {
                this.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).allowEdit(true);
                this.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(true);
                this.object(fieldNum(AgreementHeaderDefault, ETGDeliveryTermSales)).allowEdit(true);
                this.object(fieldNum(AgreementHeaderDefault, ETGDeliveryTermSales)).mandatory(true);
            }
            else
            {
                this.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).allowEdit(true);
                this.object(fieldNum(AgreementHeaderDefault, DeliveryTerm)).mandatory(false);
                this.object(fieldNum(AgreementHeaderDefault, ETGDeliveryTermSales)).allowEdit(false);
                this.object(fieldNum(AgreementHeaderDefault, ETGDeliveryTermSales)).mandatory(false);
            }
        }

    }

    return ret;
}
